import React from 'react';
import { useNotes } from '../../context/NotesContext';
import ExportButton from './ExportButton';

const TopBar = ({ note, onBack }) => {
  const { updateCurrentNoteLocally, saveCurrentNote } = useNotes();

  const handleSave = async () => {
    if (note) {
      try {
        await saveCurrentNote();
      } catch (error) {
        console.error('Failed to save note:', error);
      }
    }
  };

  const handleTitleChange = (title) => {
    if (note) {
      updateCurrentNoteLocally({ title });
    }
  };

  return (
    <div className="top-bar">
      <div className="top-bar__left">
        {onBack && (
          <button className="top-bar__btn top-bar__btn--back" onClick={onBack}>
            ← Back
          </button>
        )}
        <input
          type="text"
          className="top-bar__title"
          value={note?.title || ''}
          onChange={(e) => handleTitleChange(e.target.value)}
          placeholder="Note title..."
        />
      </div>

      <div className="top-bar__right">
        <button 
          className="top-bar__btn top-bar__btn--save"
          onClick={handleSave}
          disabled={!note}
          title="Save note (Ctrl+S)"
        >
          Save
        </button>
        <ExportButton note={note} />
      </div>
    </div>
  );
};

export default TopBar;
